import{_ as t,o as a,c as i,ag as r}from"./chunks/framework.uucRfDOW.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"OmniGuard","text":"A friendly helper for Laravel","tagline":"Lightweight, easy to use, and mission-ready.","image":{"src":"/shield.svg","alt":"OmniGuard Shield"},"actions":[{"theme":"brand","text":"Installation Guide","link":"/docs/v1/installation"},{"theme":"alt","text":"Usage Guide","link":"/docs/v1/usage"}]},"features":[{"icon":"🛡️","title":"Reliable Core","details":"Architecture focused on stability with zero external runtime dependencies. No version conflicts, ever."},{"icon":"🧠","title":"Heuristic Brain","details":"Automated Multi-Discovery Hub maps your codebase using semantic synonym mapping and Fuzzy matching."},{"icon":"⚡","title":"Fast Performance","details":"Efficient O(1) performance using binary integer comparison. Optimized for $1 budget hosting."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function o(s,e,l,u,d,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<blockquote><p><strong>Reliable authorization, simple setup, and fast performance.</strong></p></blockquote><p>Welcome to the official documentation for <strong>OmniGuard</strong>, a friendly and helpful authorization manager for Laravel.</p><h2 id="how-we-help" tabindex="-1">How we help <a class="header-anchor" href="#how-we-help" aria-label="Permalink to &quot;How we help&quot;">​</a></h2><p>OmniGuard is a tool built to help you manage security in your Laravel application without the headache. We focus on:</p><p>By keeping things simple, we eliminate version conflicts, reduce memory overhead, and make your application easier to maintain.</p><h2 id="key-pillars" tabindex="-1">Key Pillars <a class="header-anchor" href="#key-pillars" aria-label="Permalink to &quot;Key Pillars&quot;">​</a></h2><ul><li><strong>💎 Helpful Core</strong>: Zero runtime dependencies on external permission packages.</li><li><strong>🧠 Intelligent Discovery</strong>: Automatic codebase scanning that helps you map permissions without manual entry.</li><li><strong>⚡ Fast Performance</strong>: Scalable performance using binary integer comparison.</li><li><strong>🏢 Multi-Tenant Support</strong>: Built-in isolation for complex multi-user environments.</li><li><strong>🛡️ Reliability Protocols</strong>: Simple fail-safes for critical environments.</li></ul><hr><h2 id="📄-license-authority" tabindex="-1">📄 License &amp; Authority <a class="header-anchor" href="#📄-license-authority" aria-label="Permalink to &quot;📄 License &amp; Authority&quot;">​</a></h2><p>OmniGuard is protected under its standard license terms. Permission is granted for use within your application under the original branding of <strong>Ahtesham</strong> and <strong>Broadway Web Services</strong>.</p><hr><h2 id="💎-support-credits" tabindex="-1">💎 Support &amp; Credits <a class="header-anchor" href="#💎-support-credits" aria-label="Permalink to &quot;💎 Support &amp; Credits&quot;">​</a></h2><p>OmniGuard was built with care by <strong>Ahtesham</strong> and <strong>Broadway Web Services</strong>. We are committed to keeping this tool helpful and reliable for all our partners.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>To get started with OmniGuard, we recommend following the guides in order:</p><ol><li><strong><a href="./installation.html">Installation</a></strong>: Add the helpful core to your Laravel project.</li><li><strong><a href="./hierarchy.html">Hierarchy</a></strong>: Set up your roles and their ranks.</li><li><strong><a href="./heuristics.html">Discovery Brain</a></strong>: Speed up security mapping with auto-discovery.</li><li><strong><a href="./bitmasking.html">Performance</a></strong>: Learn about our ultra-fast bitmasking.</li><li><strong><a href="./usage.html">API Reference</a></strong>: Full details on how to use OmniGuard in your code.</li><li><strong><a href="./saas-multitenancy.html">SaaS &amp; Teams</a></strong>: Use OmniGuard for multi-tenant applications.</li><li><strong><a href="./security.html">Security Guide</a></strong>: Special features like Panic Mode and Impersonation.</li></ol>',16)])])}const p=t(n,[["render",o]]);export{m as __pageData,p as default};
